import{_ as a,o as e,c as d,ag as r}from"./chunks/framework.WmBmIPw-.js";const u=JSON.parse('{"title":"运筹优化","description":"","frontmatter":{},"headers":[],"relativePath":"or-opt/index.md","filePath":"or-opt/index.md","lastUpdated":1777191778000}'),h={name:"or-opt/index.md"};function i(l,t,s,o,c,n){return e(),d("div",null,[...t[0]||(t[0]=[r('<h1 id="运筹优化" tabindex="-1">运筹优化 <a class="header-anchor" href="#运筹优化" aria-label="Permalink to &quot;运筹优化&quot;">​</a></h1><p>运筹优化（Operations Research &amp; Optimization）是研究如何在有限资源下做出最优决策的学科。</p><hr><h2 id="算法目录" tabindex="-1">算法目录 <a class="header-anchor" href="#算法目录" aria-label="Permalink to &quot;算法目录&quot;">​</a></h2><h3 id="建模方法" tabindex="-1">建模方法 <a class="header-anchor" href="#建模方法" aria-label="Permalink to &quot;建模方法&quot;">​</a></h3><table tabindex="0"><thead><tr><th>主题</th><th>说明</th><th>链接</th></tr></thead><tbody><tr><td>整数规划建模技巧</td><td>逻辑约束、二选一、指示约束、布尔运算的线性化等</td><td><a href="./modeling/integer-modeling-techniques.html">查看</a></td></tr></tbody></table><h3 id="经典问题数学模型" tabindex="-1">经典问题数学模型 <a class="header-anchor" href="#经典问题数学模型" aria-label="Permalink to &quot;经典问题数学模型&quot;">​</a></h3><table tabindex="0"><thead><tr><th>问题</th><th>说明</th><th>链接</th></tr></thead><tbody><tr><td>指派问题</td><td>（待写）</td><td><a href="./classic-models/assignment-problem.html">查看</a></td></tr><tr><td>最短路问题</td><td>（待写）</td><td><a href="./classic-models/shortest-path-problem.html">查看</a></td></tr><tr><td>最大流问题</td><td>（待写）</td><td><a href="./classic-models/max-flow-problem.html">查看</a></td></tr><tr><td>最优整数解特性与幺模矩阵</td><td>（待写）</td><td><a href="./classic-models/integer-solutions-unimodular-matrices.html">查看</a></td></tr><tr><td>多商品网络流问题</td><td>（待写）</td><td><a href="./classic-models/multicommodity-network-flow.html">查看</a></td></tr><tr><td>多商品流运输问题</td><td>（待写）</td><td><a href="./classic-models/multicommodity-transportation.html">查看</a></td></tr><tr><td>设施选址问题</td><td>（待写）</td><td><a href="./classic-models/facility-location.html">查看</a></td></tr><tr><td>旅行商问题</td><td>（待写）</td><td><a href="./classic-models/traveling-salesman-problem.html">查看</a></td></tr><tr><td>车辆路径规划问题</td><td>（待写）</td><td><a href="./classic-models/vehicle-routing-problem.html">查看</a></td></tr></tbody></table><h3 id="精确算法" tabindex="-1">精确算法 <a class="header-anchor" href="#精确算法" aria-label="Permalink to &quot;精确算法&quot;">​</a></h3><p><a href="./exact/exact-algorithms.html">总览：方法关系与阅读顺序 →</a></p><table tabindex="0"><thead><tr><th>算法</th><th>说明</th><th>链接</th></tr></thead><tbody><tr><td>分支定界（Branch and Bound）</td><td>求解整数规划的经典方法，通过分支和定界剪枝搜索解空间</td><td><a href="./exact/branch-and-bound.html">查看</a></td></tr><tr><td>分支切割（Branch and Cut）</td><td>在分支定界基础上加入割平面，加速收敛</td><td><a href="./exact/branch-and-cut.html">查看</a></td></tr><tr><td>列生成（Column Generation）</td><td>求解大规模线性规划，按需生成变量列</td><td><a href="./exact/column-generation.html">查看</a></td></tr><tr><td>分支定价（Branch-and-Price）</td><td>分支定界与列生成的结合，求解大规模整数规划</td><td><a href="./exact/branch-and-price.html">查看</a></td></tr><tr><td>分支定价切割（Branch-Price-and-Cut, BPC）</td><td>在分支定价各节点上加入有效不等式（割）以收紧 LP 界</td><td><a href="./exact/branch-price-and-cut.html">查看</a></td></tr><tr><td>Dantzig-Wolfe 分解（Dantzig–Wolfe Decomposition）</td><td>将问题分解为主问题和子问题，利用块角结构</td><td><a href="./exact/dantzig-wolfe.html">查看</a></td></tr><tr><td>Benders 分解（Benders Decomposition）</td><td>将混合整数规划分解为主问题和子问题，通过割平面迭代</td><td><a href="./exact/benders.html">查看</a></td></tr><tr><td>拉格朗日（Lagrangian Relaxation）</td><td>通过松弛复杂约束，将问题分解为易求解的子问题</td><td><a href="./exact/lagrangian.html">查看</a></td></tr></tbody></table><h3 id="启发式算法" tabindex="-1">启发式算法 <a class="header-anchor" href="#启发式算法" aria-label="Permalink to &quot;启发式算法&quot;">​</a></h3><p><a href="./heuristics/heuristic-algorithms.html">总览：分类与三类的边界 →</a></p><table tabindex="0"><thead><tr><th>子类</th><th>说明</th><th>链接</th></tr></thead><tbody><tr><td>基础启发式（Simple Heuristics）</td><td>问题特化的构造/贪心/单阶段局部搜索等，常作初始解与热启动；子篇见下表</td><td><a href="./heuristics/simple/simple-heuristics.html">总览</a></td></tr><tr><td>元启发式（Metaheuristics）</td><td>通用高层迭代框架；已写 <a href="./heuristics/meta/simulated-annealing.html">模拟退火</a>、<a href="./heuristics/meta/tabu-search.html">禁忌搜索</a>、<a href="./heuristics/meta/genetic-algorithm.html">遗传算法</a>、<a href="./heuristics/meta/vns.html">变邻域搜索</a>、<a href="./heuristics/meta/iterated-local-search.html">ILS/迭代局搜</a>、<a href="./heuristics/meta/grasp.html">贪婪随机自适应搜索过程（GRASP）</a>、<a href="./heuristics/meta/particle-swarm-optimization.html">粒子群</a>、<a href="./heuristics/meta/ant-colony-optimization.html">蚁群</a>、<a href="./heuristics/meta/alns.html">ALNS/自适应大邻域</a>，其余见元启发式页</td><td><a href="./heuristics/metaheuristics.html">查看</a></td></tr><tr><td>超启发式（Hyper-heuristics）</td><td>在启发式算子/邻域层做选择或生成，强调与问题解耦、可迁移</td><td><a href="./heuristics/hyper-heuristics.html">查看</a></td></tr></tbody></table><table tabindex="0"><thead><tr><th>子篇（基础启发式）</th><th>说明</th><th>链接</th></tr></thead><tbody><tr><td>贪心（构造式）</td><td>逐步取当前最好一步的构造，不回溯</td><td><a href="./heuristics/simple/greedy-algorithm.html">查看</a></td></tr><tr><td>插入启发式</td><td>将客户逐点插入弧上，兼容 TSP/带约束 VRP</td><td><a href="./heuristics/simple/insertion-heuristics.html">查看</a></td></tr><tr><td>Clarke–Wright 节约</td><td>CVRP 边合并、按 savings 从大到小并线</td><td><a href="./heuristics/simple/clarke-wright-savings.html">查看</a></td></tr><tr><td>爬山</td><td>邻域内只接受改进、至局部最优</td><td><a href="./heuristics/simple/hill-climbing.html">查看</a></td></tr><tr><td>2-opt / 3-opt / k-opt</td><td>路径边交换邻域，常用局搜子过程</td><td><a href="./heuristics/simple/k-opt.html">查看</a></td></tr></tbody></table><h3 id="图算法" tabindex="-1">图算法 <a class="header-anchor" href="#图算法" aria-label="Permalink to &quot;图算法&quot;">​</a></h3><table tabindex="0"><thead><tr><th>算法</th><th>说明</th><th>链接</th></tr></thead><tbody><tr><td>Dijkstra</td><td>非负权图上的单源最短路，贪心+优先队列</td><td><a href="./graph/dijkstra.html">查看</a></td></tr><tr><td>Bellman-Ford</td><td>一般边权单源最短路、负边与负圈检测</td><td><a href="./graph/bellman-ford.html">查看</a></td></tr></tbody></table><p><strong>注</strong>：为与侧栏一致，<code>docs/or-opt/</code> 下已按 <code>modeling</code>（建模）、<code>classic-models</code>（经典问题数学模型）、<code>exact</code>（精确算法）、<code>heuristics</code>（启发式，内含 <code>simple</code> / <code>meta</code>）、<code>graph</code>（图算法）分文件夹存放，便于在仓库中浏览。</p><hr>',19)])])}const f=a(h,[["render",i]]);export{u as __pageData,f as default};
